const Q_GOVERNMENT_2007=[{"id": "objective>Government>2007>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a hinderance to the democratization of the United Nations?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Resistance of the big powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proliferation of weapons of mass destruction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The multiplicity of official languages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Delayed payment of annual dues by members</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The democratization of the United Nations is hindered by the resistance of the big powers. This is because these powers, which are the five permanent members of the UN Security Council (China, France, Russia, the United Kingdom, and the United States), have the power to veto any substantive resolution. This means that they can block any decision they disagree with, making it difficult for the UN to democratize.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>2007>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An essential principle that guides the activities of the United Nations is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the regulation of international trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the protection of the United States of America against terrorism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the transfer of technologies to developing countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respect for sovereign equality of member states</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The United Nations is guided by several principles, one of which is the respect for the sovereign equality of all its member states. This principle is enshrined in the UN Charter and means that all member states, regardless of their size or influence, have an equal say in the organization's decision-making processes. This principle is fundamental to the functioning of the UN and its ability to maintain international peace and security.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>2007>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The African Union was established to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">form an African High Command</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote global economic dominance by Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">address current international developments affecting Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidate Africa's position in global politics</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The African Union (AU) is a continental body consisting of the 55 member states that make up the countries of the African Continent. It was officially launched in 2002 to replace the Organisation of African Unity (OAU, 1963-1999). The main objectives of the AU include promoting unity and solidarity among African countries, accelerating political and socio-economic integration, promoting peace, security, and stability on the continent, and addressing current international developments affecting Africa. Therefore, the correct answer is 'address current international developments affecting Africa'.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OAU/AU"}, {"id": "objective>Government>2007>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A principal defect of the commonwealth is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of commitment by member states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of quorum at annual summits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poverty among member states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of a democratic head</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Commonwealth is a political association of 54 member states, nearly all of which are former territories of the British Empire. One of the principal defects of the Commonwealth is the lack of commitment by member states. This is because the Commonwealth operates on a consensus model, meaning all members have to agree before action can be taken. This can lead to a lack of commitment by some member states, which can hinder the effectiveness of the organization. Therefore, the correct answer is 'lack of commitment by member states'.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : COMMONWEALTH"}, {"id": "objective>Government>2007>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria declared that she would not attend OAU summit in Tripoli in 1982 unless</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Colonel Gaddafi resigned as the Libyan Head of State </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Libya withdrew her troops from Chad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">President Shehu Shagari became the chairman of OAU</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cameroun was suspended for killing Nigeria soldiers at Bakassi</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In 1982, Nigeria threatened to boycott the OAU summit in Tripoli unless Libya withdrew her troops from Chad. This was due to the Chadian-Libyan conflict where Libya had invaded Chad. Nigeria, being a major player in African politics, used this as a diplomatic tool to force Libya to withdraw its troops from Chad.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : OAU/AU"}, {"id": "objective>Government>2007>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's non-aligned policy was criticized because of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS Treaty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear Test Ban Treaty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anglo-Nigerian Defence Pact</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Non-proliferation Treaty</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's non-aligned policy was criticized because of the Anglo-Nigerian Defence Pact. The non-aligned movement was a group of states which were not formally aligned with or against any major power bloc. However, the Anglo-Nigerian Defence Pact was seen as a contradiction to this policy as it was a bilateral agreement with a major power, the United Kingdom. This led to criticisms that Nigeria was not truly non-aligned.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}, {"id": "objective>Government>2007>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">NEPAD was adopted during the OAU summit held in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tunis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lusaka</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cario</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abuja</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The New Partnership for Africa's Development (NEPAD) was adopted during the Organisation of African Unity (OAU) summit held in Lusaka, Zambia in July 2001. NEPAD is a socio-economic development tool used by the African Union (AU), which replaced the OAU, to address development challenges in Africa.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OAU/AU"}, {"id": "objective>Government>2007>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's interest in teaming up with other developing countries in the world is predicated on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">her desire to consume more manufactured goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">her desire to produce more raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preserving her independence and promoting development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">getting a permanent seat in the United Nations Security Council</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's interest in teaming up with other developing countries is primarily based on preserving her independence and promoting development. This is because by collaborating with other developing countries, Nigeria can share and learn from their experiences, strategies, and policies that have led to their development. This collaboration also helps in maintaining and strengthening their sovereignty and independence by reducing their dependence on developed countries.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH DEVELOPING COUNTRIES"}, {"id": "objective>Government>2007>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was once Nigeria's permanent representative at the United Nations?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Professor Bolaji Akinyemi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Major General Ike Nwachukwu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Professor Jubril Aminu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Major General Joseph Garba</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Major General Joseph Garba was Nigeria's permanent representative at the United Nations from 1984 to 1989. He was a Nigerian general, diplomat, and politician who served as President of the United Nations General Assembly from 1989 to 1990.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS"}, {"id": "objective>Government>2007>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethics and accountability in government can be guaranteed through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">legislative cooperation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive and judicial immunity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">due process and transparency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">administrative reforms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethics and accountability in government can be guaranteed through due process and transparency. Due process ensures that all actions and decisions taken by public officials are done in accordance with the law, while transparency ensures that the actions and decisions of public officials are open to scrutiny by the public. This helps to prevent corruption and promote accountability in government.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : ETHICS AND ACCOUNTABILITY IN PUBLIC OFFICE"}, {"id": "objective>Government>2007>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of law-making by the legislature begins with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">initiating a bill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commencing debate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a public hearing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the first reading</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of law-making, also known as legislation, typically begins with the initiation of a bill. A bill is a draft of a legislative proposal, which becomes law when it receives the necessary approval and sanctioning. The process usually involves several stages including the initiation, debate, committee scrutiny, voting, and assent. Therefore, the correct answer is 'initiating a bill'.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : JOHN MACPHERSON CONSTITUTION 1951"}, {"id": "objective>Government>2007>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A non-permanent feature of a state is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A state is typically defined by four key elements: population, territory, government, and sovereignty. Among these, government is considered a non-permanent feature because it can change over time through elections, revolutions, or other forms of political change. Society, population, and territory are generally more stable and permanent features of a state. Therefore, the correct answer is 'government'.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>2007>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ancient Greeks practiced</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">direct democracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">representative democracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberal democracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">benevolent dictatorship</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ancient Greeks practiced direct democracy. In a direct democracy, citizens themselves vote on legislation and policy initiatives, rather than electing representatives to make decisions on their behalf. This form of democracy was practiced in ancient Greek city-states, most notably Athens.</div>", "topic": "FORMS OF GOVERNMENT : DEMOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2007>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formation of confederations is based primarily on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hegemonic considerations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">historical reasons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">security considerations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geographical factors</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formation of confederations is primarily based on security considerations. A confederation is a union of sovereign states, united for purposes of common action often in relation to other states. The need for collective security, which involves the pooling of resources to defend against external threats, is a key reason for the formation of such alliances.</div>", "topic": "STRUCTURES OF GOVERNANCE : CONFEDERAL FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>2007>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The declaration of election results is the exclusive duty of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political party chairmen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electoral commissions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chief justices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">election petition tribunals</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The declaration of election results is the exclusive duty of the electoral commissions. In many democratic countries, an independent electoral commission is responsible for overseeing and implementing all electoral processes, including the declaration of election results. This is to ensure transparency, credibility, and fairness in the electoral process.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2007>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The traditions of a people that shape their government and politics represent their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political culture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">political ideology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political acculturation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political socialization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The traditions of a people that shape their government and politics represent their political culture. Political culture refers to the attitudes, beliefs, values, and practices that are held by a population that influence their political behavior. It includes the ways in which people think about politics and government, and it is shaped by their historical experiences, traditions, and cultural values.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL PROCESSES: POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>2007>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Karl Marx, the mode of production that precedes capitalism in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mercantilism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communalism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Karl Marx, the mode of production that precedes capitalism is feudalism. Marx's theory of history, also known as historical materialism, states that society's economic system fundamentally determines the political and intellectual life of that society. In his theory, he outlined several stages of development in Western societies, which include primitive communism, ancient society, feudalism, capitalism, and then socialism and communism. Therefore, feudalism is the correct answer.</div>", "topic": "POLITICAL IDEOLOGIES : COMMUNISM"}, {"id": "objective>Government>2007>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The executive is mainly concerned with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">confirmation of appointments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">approval of treaties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">approval of budgets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">implementation of policies</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The executive branch of government is primarily concerned with the implementation of policies. While the executive does have roles in the confirmation of appointments, approval of treaties, and approval of budgets, its main function is to enforce laws and policies that have been passed by the legislative branch. This includes everything from implementing national security measures to enforcing environmental regulations. Therefore, the correct answer is 'implementation of policies'.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2007>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinguishing feature of a federal state is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a written constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resource control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">separation of powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultural diversity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A distinguishing feature of a federal state is a written constitution. A federal state is a type of government where power is divided between the national government and other smaller regional governments. This division of powers is usually outlined in a written constitution, which serves as the supreme law of the land. Therefore, a written constitution is a distinguishing feature of a federal state.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM"}, {"id": "objective>Government>2007>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The recognition and general acceptance of the right to rule in a country based on laid-down regulations is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">traditional authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constitutional authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sovereign authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legitimate authority</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The recognition and general acceptance of the right to rule in a country based on laid-down regulations is known as legitimate authority. Legitimate authority refers to a type of power that is recognized as rightful and just by those over whom it is exercised. It is derived from the belief that a rule, institution, or leader has the right to govern, which is often based on the norms and laws of the society.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2007>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A political ideology that advocates extreme nationalism and suppression of individual liberties is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">socialism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">communism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudalism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fascism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fascism is a political ideology that advocates extreme nationalism and suppression of individual liberties. It is a form of far-right, authoritarian political ideology that is characterized by dictatorial power, forcible suppression of opposition, and strong regimentation of society and the economy. Socialism, communism, and feudalism do not necessarily advocate for extreme nationalism and suppression of individual liberties.</div>", "topic": "POLITICAL IDEOLOGIES : FASCISM"}, {"id": "objective>Government>2007>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a democracy, a major setback in the judicial process is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political neutrality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of professionalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">freedom from punishment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate material resources</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a democracy, a major setback in the judicial process is inadequate material resources. This is because the judicial process requires sufficient resources to function effectively. These resources include adequate funding, infrastructure, and personnel. Without these resources, the judicial process can be slow, inefficient, and ineffective. Political neutrality, lack of professionalism, and freedom from punishment are not necessarily setbacks in the judicial process.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2007>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vote taken by the citizenry on an important political issue is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">recall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">general election</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bye-election</div>", "<div style=\"font-family:Cambria;font-size:17px;\">referendum</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A vote taken by the citizenry on an important political issue is a referendum. A referendum is a direct and universal vote in which an entire electorate is invited to vote on a particular proposal and can have nationwide or local forms. This may result in the adoption of a new policy or specific law.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2007>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constitution is classified as rigid if</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it requires special procedures to amend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its core provisions are made by decree</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all its provisions cannot be amended</div>", "<div style=\"font-family:Cambria;font-size:17px;\">any of its provisions can be amended</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A constitution is classified as rigid if it requires special procedures to amend. A rigid constitution is one that requires a special procedure for its amendment, as opposed to a flexible constitution, which can be amended through the regular legislative process. The purpose of this rigidity is to prevent changes to the constitution being made too easily, which could threaten the stability of the constitutional order.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>2007>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An exception to the mandate of the legislature is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enactment of laws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oversight of the executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">representation of the citizenry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduct of external relations</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mandate of the legislature primarily includes the enactment of laws, oversight of the executive, and representation of the citizenry. However, the conduct of external relations is typically the responsibility of the executive branch, not the legislature, making it an exception to the legislature's mandate.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2007>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the obligations of a citizen is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">obedience to the laws of the land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">active participation in partisan politics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sticking to his beliefs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loyalty to the ruling party</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A citizen's obligations include obedience to the laws of the land, paying taxes, and participating in civic duties like voting. Active participation in partisan politics, sticking to personal beliefs, or loyalty to the ruling party are not obligations but rather personal choices. Therefore, the correct answer is 'obedience to the laws of the land'.</div>", "topic": "CITIZENSHIP : DUTIES AND OBLIGATIONS OF CITIZENS"}, {"id": "objective>Government>2007>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the objectives of a multiparty system is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent rigging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide alternatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avoid ethnicity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eliminate corruption</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A multiparty system is a system in which multiple political parties across the political spectrum run for national election, and all have the capacity to gain control of government offices, separately or in coalition. The main objective of a multiparty system is to provide alternatives to the citizens. It allows for different parties to present their different policies and ideologies to the public, and the public can then make an informed choice about which party they believe will best serve their interests. Therefore, the correct answer is 'provide alternatives'.</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS"}, {"id": "objective>Government>2007>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constitution formulated and imposed on a country without popular participation is said to be created by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fiat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directives </div>", "<div style=\"font-family:Cambria;font-size:17px;\">command</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decree</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A constitution that is formulated and imposed on a country without popular participation is said to be created by fiat. The term 'fiat' is a Latin word that means 'let it be done'. In this context, it refers to an arbitrary order issued by a government or a ruler without the participation of the people. Therefore, the correct answer is 'fiat'.</div>", "topic": "CONSTITUTION"}, {"id": "objective>Government>2007>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a parliamentary system, the term shadow cabinet is often used to refer to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">back-benchers in the house</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deputy prime ministers and assistant minister</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rebellious members of the ruling party</div>", "<div style=\"font-family:Cambria;font-size:17px;\">portfolio designates of the party in opposition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a parliamentary system, the term 'shadow cabinet' is often used to refer to the portfolio designates of the party in opposition. The shadow cabinet is a feature of the Westminster system of government. It consists of a senior group of opposition spokespeople who, under the leadership of the Leader of the Opposition, form an alternative cabinet to that of the government, and whose members shadow or mirror the positions of each individual member of the Cabinet. It is the Shadow Cabinet's responsibility to scrutinize the policies and actions of the government, as well to offer an alternative program.</div>", "topic": "FORMS OF GOVERNMENT : PARLIAMENTARY SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>2007>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following made the earliest contact with the Nigerian society?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Portuguese</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Germans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The British</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The French</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Portuguese made the earliest contact with the Nigerian society. They arrived in Nigeria in the late 15th century during the Age of Discovery. The Portuguese explorer, João de Santarém, discovered the Lagos lagoon in 1472. The Portuguese were the first Europeans to engage in trade with the peoples of what is now Nigeria, and they established a number of trading posts on the coast.</div>", "topic": "IMPERIALIST PENETRATION : COMPARISON OF BRITISH AND FRENCH COLONIAL ADMINISTRATION"}, {"id": "objective>Government>2007>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The adoption of a federal system of government in Nigeria under colonial rule was necessitated mainly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">geographical proximity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">administrative convenience</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultural diversity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vast economic resources</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The adoption of a federal system of government in Nigeria under colonial rule was necessitated mainly by cultural diversity. Nigeria is a country with over 250 ethnic groups, each with its unique language, customs, and traditions. This diversity made it difficult for a unitary system of government to effectively manage the affairs of the country. Therefore, a federal system of government, which allows for power to be shared among the central government and the states or regions, was adopted to accommodate this diversity.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM"}, {"id": "objective>Government>2007>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public corporations are established mainly to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">offer free services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make profit for government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit jobs for the unemployed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide services at subsidized rates</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public corporations are established mainly to provide services at subsidized rates. Public corporations, also known as public sector organizations, are entities that are owned and operated by the government. They are established to provide essential services to the public at affordable rates. These services may include utilities like water and electricity, transportation, healthcare, and education. The aim is not to make profit but to ensure that all citizens have access to these basic services.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS"}, {"id": "objective>Government>2007>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Indirect rule as a British colonial policy was first introduced in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">India</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uganda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">India saw forms of indirect rule much earlier, particularly after the British East India Company began gaining control in the 18th century. <br/> </div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH PROCESS OF ACQUISITION – TRADE, MISSIONARY ACTIVITIES, COMPANY RULE, CROWN COLONY, PROTECTORATE"}, {"id": "objective>Government>2007>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Following the 1976 Local Government Reform is Nigeria, the local governments were empowered to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promulgate edicts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promulgate and enforce bye-laws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appoint and dismiss chairmen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appoint and dismiss directors of personnel</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 1976 Local Government Reform in Nigeria was a major restructuring of the local government system in the country. One of the key changes was the empowerment of local governments to promulgate and enforce bye-laws. This gave them a degree of autonomy and allowed them to manage local affairs more effectively. Bye-laws are laws that are made by a local authority and apply only within their specific geographical area.</div>", "topic": "LOCAL GOVERNMENT :FEATURES OF LOCAL GOVERNMENT REFORMS 1976, 1989 - STRUCTURE, FUNCTIONS, FINANCE AND INTER-GOVERNMENTAL RELATIONS"}, {"id": "objective>Government>2007>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Nigerian Constitution, the powers to create local governments lie with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">state governors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Presidency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">State Houses of Assembly</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Nigerian Constitution, the power to create local governments lies with the State Houses of Assembly. This is because the constitution gives the state the power to create, merge, or alter the boundaries of local governments as they deem fit.</div>", "topic": "LOCAL GOVERNMENT"}, {"id": "objective>Government>2007>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pre-colonial Igbo political system was largely </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">republican </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dictatorial </div>", "<div style=\"font-family:Cambria;font-size:17px;\">monarchical </div>", "<div style=\"font-family:Cambria;font-size:17px;\">authoritarian</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pre-colonial Igbo political system was largely republican. This means that it was a system where the head of state is an elected or nominated president rather than a monarch. The Igbo political system was decentralized and democratic in nature, with decisions made by a general assembly of all adult males.</div>", "topic": "PRE-COLONIAL POLITICS"}, {"id": "objective>Government>2007>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following states were created in 1996?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Akwa Ibom and Kogi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gombe and Zamfara</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamawa and Ekiti</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ebonyi and Osun</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The states of Gombe and Zamfara were created in 1996 by the military regime of General Sani Abacha. Akwa Ibom and Kogi were created in 1987 and 1991 respectively. Adamawa and Ekiti were created in 1991 and 1996 respectively. Ebonyi and Osun were created in 1996 and 1991 respectively.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : CREATION OF STATES – 1963, 1967, 1976, 1987, 1991, 1996"}, {"id": "objective>Government>2007>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Acculturation in colonial administration was associated with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">French policy of assimilation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">British policy of direct rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">French policy of association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">British indirect rule system</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Acculturation in colonial administration was associated with the French policy of assimilation. This policy aimed at making the colonized people adopt the French culture, language, and way of life. The British policy of direct rule and indirect rule system, on the other hand, allowed the colonized people to maintain their culture and traditions under the supervision of British officials. The French policy of association was a modification of the policy of assimilation, allowing for some degree of cultural diversity.</div>", "topic": "IMPERIALIST PENETRATION : THE FRENCH COLONIAL ADMINISTRATIVE POLICY – ASSIMILATION AND ASSOCIATION"}, {"id": "objective>Government>2007>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Military disengagement from politics is always preceded by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the retirement of military personnel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the making of a new constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in worker's salaries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the establishment of more universities</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Military disengagement from politics is usually preceded by the making of a new constitution. This is because a new constitution often outlines the structure and function of the government, including the role of the military, which is typically to defend the country rather than to engage in politics.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS : PROCESSES OF MILITARY DISENGAGEMENT"}, {"id": "objective>Government>2007>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of federal character was first enunciated in  the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1989 Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1963 Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1999 Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1979 Constitution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of federal character was first enunciated in the 1979 Constitution of Nigeria. This principle was introduced to ensure that appointments to public service institutions fairly reflect the linguistic, ethnic, religious, and geographic diversity of the country.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : RATIONALE FOR A FEDERAL SYSTEM"}, {"id": "objective>Government>2007>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The final court of appeal in Nigeria during the colonial era was the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">privy council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supreme court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appeal court</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the colonial era in Nigeria, the final court of appeal was the Privy Council. The Privy Council is a body of advisors to the British monarch. Its judicial committee serves as the highest court of appeal for several independent Commonwealth countries, the UK overseas territories, and the British Crown dependencies.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2007>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Native Authority system of local Administration was introduced by the British in Nigeria to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">introduced Western education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure the administration of justice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">empower traditional rulers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitate tax collection</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Native Authority system of local Administration was introduced by the British in Nigeria primarily to facilitate tax collection. This system allowed the British to indirectly rule and control the local population through traditional rulers, who were given the responsibility of tax collection in their respective regions.</div>", "topic": "LOCAL GOVERNMENT :FEATURES OF LOCAL GOVERNMENT REFORMS 1976, 1989 - STRUCTURE, FUNCTIONS, FINANCE AND INTER-GOVERNMENTAL RELATIONS"}, {"id": "objective>Government>2007>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major objecitive of the manifesto of the People's Redemption Party in the Second Republic was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">housing for all</div>", "<div style=\"font-family:Cambria;font-size:17px;\">welfare of the nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emancipation of the masses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free education</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The People's Redemption Party (PRP) was a major political party in Nigeria during the Second Republic (1979-1983). The party was markedly leftist and its main objective was the emancipation of the masses. This means freeing the common people in a society from political, social, or economic restrictions or discrimination.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : SECOND REPUBLIC"}, {"id": "objective>Government>2007>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The privatization of public corporations in Nigeria is undertaken by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bureau of Public Enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Stock Exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Civil Service Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Executive Council</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The privatization of public corporations in Nigeria is undertaken by the Bureau of Public Enterprises (BPE). The BPE is a Nigerian governmental agency tasked with the responsibility of implementing the policy of the Federal Government to divest its interest in parastatals, agencies, and other government businesses.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS : DEREGULATION, PRIVATIZATION, COMMERCIALIZATION – OBJECTIVES, FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2007>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main goal of NNDP was to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">agitate for Nigeria's Independence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">achieve franchise for Nigerians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secure limited autonomy for the natives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote economic stability</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main goal of the Nigerian National Development Plan (NNDP) was to promote economic stability and development in Nigeria. </div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : FIRST REPUBLIC"}, {"id": "objective>Government>2007>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Structural Adjustment Programme was introduced by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Babangida regime</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abacha regime</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Murtala/Obasanjo regime</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Buhari regime</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Structural Adjustment Programme (SAP) was introduced by the Babangida regime in Nigeria. The SAP was an economic programme that sought to alter and restructure the Nigerian economy. It was introduced in 1986 by the then military president, General Ibrahim Babangida, due to the economic hardship experienced in the country.</div>", "topic": "ECONOMIC POLICIES AND DEVELOPMENT STRATEGIES : STRUCTURAL ADJUSTMENT PROGRAMME (SAP)"}, {"id": "objective>Government>2007>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Ogboni cult in the pre-colonial Yoruba political system played the role of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">police</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislature</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ogboni cult in the pre-colonial Yoruba political system played the role of the judiciary. They were responsible for the administration of justice and the interpretation of laws.</div>", "topic": "PRE-COLONIAL POLITICS : YORUBA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>2007>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The head of the electoral body that conducted the June 12, 1993 elections was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Humphrey Nwosu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ovie-Whiskey</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eme Awa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dagogo-Jack</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The head of the electoral body that conducted the June 12, 1993 elections was Humphrey Nwosu. He was the chairman of the National Electoral Commission (NEC) at the time.</div>", "topic": "ELECTORAL PROCESS"}, {"id": "objective>Government>2007>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Deregulation as an economic policy borders on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the removal of subsidies on public utilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the removal of restrictions and extension of competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">privatization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercialization</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deregulation as an economic policy refers to the reduction or elimination of government power in a particular industry, usually enacted to create more competition within the industry. It involves the removal of restrictions and extension of competition, not necessarily the removal of subsidies, privatization or commercialization.</div>", "topic": "ECONOMIC POLICY"}, {"id": "objective>Government>2007>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethnic politics in Nigeria can be traced to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Macpherson Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lyttleton Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clifford Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Richards Constitution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethnic politics in Nigeria can be traced back to the Macpherson Constitution of 1951. This constitution introduced regionalism and allowed each region to develop at its own pace, thereby creating a sense of ethnic consciousness and competition among the different ethnic groups in Nigeria.</div>", "topic": "ETHNIC POLITICS"}];
